  }, [amIVoted, gameFlow.voted, myId]);

  const canVote = gameFlow.isVote && !isIDead && !isIGM && !rootStore.isIBlocked;
  const isVotingActive = gameFlow.proposed.length > 1 && gameFlow.isVote;

