import { observer } from "mobx-react-lite";
import { useEffect } from "react";

import { useCustomVideo } from "@/hooks/useCustomVideo.ts";
import { useVideoSettings } from "@/hooks/useVideoSettings.ts";

type VideoConfigLoaderProps = {
  originalStream: MediaStream | null;
  gameId: string;
  onNeedConfig: () => void;
};

export const VideoConfigLoader = observer(
  ({ originalStream, gameId, onNeedConfig }: VideoConfigLoaderProps) => {
    const { getSavedSettings } = useVideoSettings(gameId);
    const { applySettings } = useCustomVideo(originalStream);

    useEffect(() => {
      if (!originalStream) return;

      const savedSettings = getSavedSettings();

      if (savedSettings) {
        applySettings(savedSettings);
      } else {
        onNeedConfig();
      }
    }, [originalStream, getSavedSettings, applySettings, onNeedConfig]);

    return null;
  }
);

VideoConfigLoader.displayName = "VideoConfigLoader";

import { observer } from "mobx-react-lite";
import { useCallback, useMemo } from "react";

import {
  useAddUserToProposedMutation,
  useVoteForUserMutation,
} from "@/api/game/queries.ts";
import { useVoteResult } from "@/hooks/useVoteResult.ts";
import { rootStore } from "@/store/rootStore.ts";
import { SoundEffect } from "@/store/soundStore.ts";
import { UserId } from "@/types/user.types.ts";
import { ButtonSize, ButtonVariant } from "@/UI/Button/ButtonTypes.ts";
import { VoteIcon } from "@/UI/VoteIcon";

import styles from "./VoteFlow.module.scss";

type VoteFlowProps = {
  isMyStream: boolean;
  userId: UserId;
};

export const VoteFlow = observer(({ isMyStream, userId }: VoteFlowProps) => {
  const { usersStore, gamesStore, isIGM, isIDead, isISpeaker, soundStore } = rootStore;
  const { myId, getUser } = usersStore;
  const { isUserGM, speaker, gameFlow, activeGameAlivePlayers, activeGameId } =
    gamesStore;
  const { isVote, proposed, voted, isExtraSpeech } = gameFlow;
  const { isIBlocked } = rootStore;
  const { playSfx } = soundStore;
  const { mutate: voteForUser } = useVoteForUserMutation();
  const { mutate: addUserToProposed } = useAddUserToProposedMutation();

  const votesForThisUser = useMemo(
    () => voted?.[userId] ?? [],
    [voted, userId]
  );

  const amIVoted = useMemo(() => {
    return Object.values(voted ?? {})
      .flat()
      .includes(myId);
  }, [voted, myId]);

  const isUserAddedToVoteList = useMemo(
    () => (userId ? proposed.includes(userId) : false),
    [proposed, userId]
  );

  const isThisUserProposed = useMemo(() => {
    return proposed.includes(userId);
  }, [proposed, userId]);

  const isVotedByThisUser = useMemo(() => {
    return amIVoted && votesForThisUser.includes(myId);
  }, [amIVoted, votesForThisUser, myId]);

  const isCurrentUserGM = isUserGM(userId);

  const shouldShowProposeIcon =
    !!speaker &&
    (isISpeaker || isIGM) &&
    !isMyStream &&
    !isCurrentUserGM &&
    !isExtraSpeech &&
    !isIDead;

  const shouldShowVoteIcon =
    isVote && proposed.includes(userId) && !isIDead && !isIBlocked;

  const onPropose = useCallback(() => {
    if (
      (myId !== speaker && !isUserGM(myId)) ||
      !userId ||
      !activeGameId ||
      isThisUserProposed
    )
      return;

    addUserToProposed({ gameId: activeGameId, userId });
  }, [
    activeGameId,
    addUserToProposed,
    isThisUserProposed,
    isUserGM,
    myId,
    speaker,
    userId,
  ]);

  const onVote = useCallback(() => {
    if (!userId || !myId || !activeGameId) return;
    if (amIVoted || isIGM || isIBlocked) return;

    voteForUser({
      gameId: activeGameId,
      targetUserId: userId,
      voterId: myId,
    });
    playSfx(SoundEffect.Vote);
  }, [userId, myId, activeGameId, amIVoted, isIGM, voteForUser, playSfx]);

  useVoteResult({
    alivePlayers: activeGameAlivePlayers,
    isIGM,
  });

  return (
    <>
      {shouldShowProposeIcon && (
        <VoteIcon
          className={styles.voteIcon}
          size={ButtonSize.Small}
          variant={ButtonVariant.Secondary}
          isVoted={isUserAddedToVoteList}
          onClick={onPropose}
        />
      )}

      {shouldShowVoteIcon && (
        <div className={styles.iconContainer}>
          <VoteIcon
            className={styles.voteIcon}
            size={ButtonSize.Small}
            variant={ButtonVariant.Secondary}
            onClick={onVote}
            isVoted={isVotedByThisUser}
          />

          {votesForThisUser.length > 0 && (
            <p className={styles.voteCounter}>{votesForThisUser.length}</p>
          )}
        </div>
      )}

      {votesForThisUser.length > 0 && isVote && (
        <ul className={styles.voteList}>
          {votesForThisUser.map((id) => (
            <li key={id}>{getUser(id)?.nikName || "Anonimus"}</li>
          ))}
        </ul>
      )}
    </>
  );
});

import { observer } from "mobx-react-lite";
import { useCallback, useMemo } from "react";

import {
  useAddUserToProposedMutation,
  useVoteForUserMutation,
} from "@/api/game/queries.ts";
import { useVoteResult } from "@/hooks/useVoteResult.ts";
import { rootStore } from "@/store/rootStore.ts";
import { SoundEffect } from "@/store/soundStore.ts";
import { UserId } from "@/types/user.types.ts";
import { ButtonSize, ButtonVariant } from "@/UI/Button/ButtonTypes.ts";
import { VoteIcon } from "@/UI/VoteIcon";

import styles from "./VoteFlow.module.scss";

type VoteFlowProps = {
  isMyStream: boolean;
  userId: UserId;
};

export const VoteFlow = observer(({ isMyStream, userId }: VoteFlowProps) => {
  const { usersStore, gamesStore, isIGM, isIDead, isISpeaker, soundStore } = rootStore;
  const { myId, getUser } = usersStore;
  const { isUserGM, speaker, gameFlow, activeGameAlivePlayers, activeGameId, setToProposed, addVoted } =
    gamesStore;
  const { isVote, proposed, voted, isExtraSpeech } = gameFlow;
  const { isIBlocked } = rootStore;
  const { playSfx } = soundStore;
  const { mutate: voteForUser, isPending: isVoting } = useVoteForUserMutation();
  const { mutate: addUserToProposed, isPending: isAddingToProposed } = useAddUserToProposedMutation();

  const votesForThisUser = useMemo(
    () => voted?.[userId] ?? [],
    [voted, userId]
  );

  const amIVoted = useMemo(() => {
    return Object.values(voted ?? {})
      .flat()
      .includes(myId);
  }, [voted, myId]);

  const isUserAddedToVoteList = useMemo(
    () => (userId ? proposed.includes(userId) : false),
    [proposed, userId]
  );

  const isThisUserProposed = useMemo(() => {
    return proposed.includes(userId);
  }, [proposed, userId]);

  const isVotedByThisUser = useMemo(() => {
    return amIVoted && votesForThisUser.includes(myId);
  }, [amIVoted, votesForThisUser, myId]);

  const isCurrentUserGM = isUserGM(userId);

  const shouldShowProposeIcon =
    !!speaker &&
    (isISpeaker || isIGM) &&
    !isMyStream &&
    !isCurrentUserGM &&
    !isExtraSpeech &&
    !isIDead;

  const shouldShowVoteIcon =
    isVote && proposed.includes(userId) && !isIDead && !isIBlocked;

  const onPropose = useCallback(() => {
    if (
      (myId !== speaker && !isUserGM(myId)) ||
      !userId ||
      !activeGameId ||
      isThisUserProposed ||
      isAddingToProposed
    )
      return;

    setToProposed(userId);
    addUserToProposed({ gameId: activeGameId, userId });
  }, [
    activeGameId,
    addUserToProposed,
    isThisUserProposed,
    isAddingToProposed,
    isUserGM,
    myId,
    setToProposed,
    speaker,
    userId,
  ]);

  const onVote = useCallback(() => {
    if (!userId || !myId || !activeGameId) return;
    if (amIVoted || isIGM || isIBlocked || isVoting) return;

    addVoted({ targetUserId: userId, voterId: myId });
    voteForUser({
      gameId: activeGameId,
      targetUserId: userId,
      voterId: myId,
    });
    playSfx(SoundEffect.Vote);
  }, [userId, myId, activeGameId, amIVoted, isIGM, isIBlocked, isVoting, addVoted, voteForUser, playSfx]);

  useVoteResult({
    alivePlayers: activeGameAlivePlayers,
    isIGM,
  });

  return (
    <>
      {shouldShowProposeIcon && (
        <VoteIcon
          className={styles.voteIcon}
          size={ButtonSize.Small}
          variant={ButtonVariant.Secondary}
          isVoted={isUserAddedToVoteList}
          onClick={onPropose}
        />
      )}

      {shouldShowVoteIcon && (
        <div className={styles.iconContainer}>
          <VoteIcon
            className={styles.voteIcon}
            size={ButtonSize.Small}
            variant={ButtonVariant.Secondary}
            onClick={onVote}
            isVoted={isVotedByThisUser}
          />

          {votesForThisUser.length > 0 && (
            <p className={styles.voteCounter}>{votesForThisUser.length}</p>
          )}
        </div>
      )}

      {votesForThisUser.length > 0 && isVote && (
        <ul className={styles.voteList}>
          {votesForThisUser.map((id) => (
            <li key={id}>{getUser(id)?.nikName || "Anonimus"}</li>
          ))}
        </ul>
      )}
    </>
  );
});

import { makeAutoObservable, toJS } from "mobx";
import { makePersistable } from "mobx-persist-store";

import { UserId } from "@/types/user.types.ts";

import { initialGameFlow } from "../helpers/createGameObj.ts";
import {
  IGame,
  IGameFlow,
  IGameShort,
  NightRoles,
  Roles,
} from "../types/game.types.ts";

export class GamesStore {
  _games: IGameShort[] = [];
  _activeGame: IGame | null = null;

  constructor() {
    makeAutoObservable(this, {}, { autoBind: true });
    void makePersistable(this, {
      name: "Users_mobx_gameFlow",
      properties: ["_games", "_activeGame"],
      storage: sessionStorage,
    });
  }

  setGames(games: IGameShort[]) {
    this._games = games;
  }

  updateGames(newGame: IGameShort) {
    const isGameExist = this._games.some((game) => game.id === newGame.id);

    if (!isGameExist) {
      this._games = [...this._games, newGame];

      return;
    }

    this._games = this._games.map((game) =>
      game.id === newGame.id ? newGame : game
    );
  }

  updateGame(game: IGame) {
    this._activeGame = game;
  }

  removeActiveGame() {
    this._activeGame = null;
  }

  updateGameFlow(newFlow: Partial<IGameFlow>) {
    const flow = this._activeGame?.gameFlow;

    if (!flow) return;

    this.updateGame({
      ...this._activeGame,
      gameFlow: { ...flow, ...newFlow },
    } as IGame);
  }

  setToProposed(playerId: UserId) {
    const proposed = this._activeGame?.gameFlow?.proposed;

    if (!proposed) return;

    const newProposed = [...proposed, playerId];

    this.updateGameFlow({ proposed: newProposed });
  }

  addVoted({
    targetUserId,
    voterId,
  }: {
    targetUserId: UserId;
    voterId: UserId;
  }) {
    const voted = this._activeGame?.gameFlow?.voted;

    if (!voted) return;

    const newVoted = {
      ...voted,
      [targetUserId]: [...(voted[targetUserId] || []), voterId],
    };

    this.updateGameFlow({ voted: newVoted });
  }

  addShoot({
    targetUserId,
    shooterId,
    shot,
  }: {
    targetUserId: UserId;
    shooterId: UserId;
    shot?: { x: number; y: number };
  }) {
    const shoot = this._activeGame?.gameFlow?.shoot ?? {};
    const existing = shoot[targetUserId] ?? { shooters: [], shots: [] };
    const defaultShot = { x: 50, y: 50 };

    const newShoot = {
      ...shoot,
      [targetUserId]: {
        shooters: [...existing.shooters, shooterId],
        shots: [...existing.shots, shot ?? defaultShot],
      },
    };

    this.updateGameFlow({ shoot: newShoot });
  }

  isUserGM(userId?: string) {
    if (!userId) return false;

    return this.activeGameGm === userId;
  }

  get activeGame() {
    return toJS(this._activeGame);
  }

  get activeGameId(): string | undefined {
    return this.activeGame?.id;
  }

  get activeGameGm() {
    return this.activeGame?.gm;
  }

  get activeGameOwner() {
    return this.activeGame?.owner;
  }

  get activeGamePlayers() {
    return toJS(this.activeGame?.players) ?? [];
  }

  get activeGamePlayersWithoutGM() {
    return this.activeGamePlayers.filter(
      (player) => player !== this.activeGameGm
    );
  }

  get activeGameKilledPlayers() {
    return toJS(this.gameFlow.killed) ?? [];
  }

  get activeGameAlivePlayers() {
    return this.activeGamePlayersWithoutGM.filter(
      (player) => !this.activeGameKilledPlayers.includes(player)
    );
  }

  get activeGameRoles() {
    const activeGame = this.activeGame;

    if (!activeGame) return null;

    const { mafia, sheriff, citizens, doctor, maniac, prostitute } = activeGame;

    return toJS({
      mafia,
      sheriff,
      citizens,
      doctor,
      maniac,
      prostitute,
      don: mafia?.[0],
    });
  }

  get nightRoles(): NightRoles[] {
    const roles = this.activeGameRoles;

    if (!roles) return [];

    const nightRoleOrder: NightRoles[] = [
      Roles.Mafia, Roles.Don, Roles.Sheriff, Roles.Prostitute, Roles.Doctor,
    ];

    const nightRoles = Object.entries(roles)
      .filter(([key, value]) => {
        if (!value || key === Roles.Citizen) return false;

        // If it's Mafia group but we only have 1 (who is also the Don), hide Mafia group option
        if (
          key === Roles.Mafia &&
          Array.isArray(value) &&
          value.length === 1
        ) {
          return false;
        }

        return true;
      })
      .map(([key]) => key);

    return nightRoles.sort(
      (a, b) => nightRoleOrder.indexOf(a as NightRoles) - nightRoleOrder.indexOf(b as NightRoles)
    ) as NightRoles[];
  }

  get gameFlow() {
    return toJS(this.activeGame?.gameFlow) ?? initialGameFlow;
  }

  get blockedPlayer() {
    return this.gameFlow.prostituteBlock ?? "";
  }

  get speaker() {
    return this.gameFlow.speaker;
  }

  get games() {
    return toJS(this._games);
  }

  getUserRole(id: UserId) {
    const roles = this.activeGameRoles;

    if (!roles) return Roles.Unknown;

    if (roles.mafia?.includes(id)) {
      return roles.mafia[0] === id ? Roles.Don : Roles.Mafia;
    }
    if (roles.citizens?.includes(id)) return Roles.Citizen;
    if (roles.sheriff === id) return Roles.Sheriff;
    if (roles.doctor === id) return Roles.Doctor;
    if (roles.maniac === id) return Roles.Maniac;
    if (roles.prostitute === id) return Roles.Prostitute;
    if (this.isUserGM(id)) return Roles.GM;

    return Roles.Unknown;
  }
}

export const gamesStore = new GamesStore();

import { makeAutoObservable, toJS } from "mobx";
import { makePersistable } from "mobx-persist-store";

import { UserId } from "@/types/user.types.ts";

import { initialGameFlow } from "../helpers/createGameObj.ts";
import {
  IGame,
  IGameFlow,
  IGameShort,
  NightRoles,
  Roles,
} from "../types/game.types.ts";

export class GamesStore {
  _games: IGameShort[] = [];
  _activeGame: IGame | null = null;

  constructor() {
    makeAutoObservable(this, {}, { autoBind: true });
    void makePersistable(this, {
      name: "Users_mobx_gameFlow",
      properties: ["_games", "_activeGame"],
      storage: sessionStorage,
    });
  }

  setGames(games: IGameShort[]) {
    this._games = games;
  }

  updateGames(newGame: IGameShort) {
    const isGameExist = this._games.some((game) => game.id === newGame.id);

    if (!isGameExist) {
      this._games = [...this._games, newGame];

      return;
    }

    this._games = this._games.map((game) =>
      game.id === newGame.id ? newGame : game
    );
  }

  updateGame(game: IGame) {
    this._activeGame = game;
  }

  removeActiveGame() {
    this._activeGame = null;
  }

  updateGameFlow(newFlow: Partial<IGameFlow>) {
    const flow = this._activeGame?.gameFlow;

    if (!flow) return;

    this.updateGame({
      ...this._activeGame,
      gameFlow: { ...flow, ...newFlow },
    } as IGame);
  }

  setToProposed(playerId: UserId) {
    const proposed = this._activeGame?.gameFlow?.proposed;

    if (!proposed) return;
    if (proposed.includes(playerId)) return;

    const newProposed = [...proposed, playerId];

    this.updateGameFlow({ proposed: newProposed });
  }

  addVoted({
    targetUserId,
    voterId,
  }: {
    targetUserId: UserId;
    voterId: UserId;
  }) {
    const voted = this._activeGame?.gameFlow?.voted;

    if (!voted) return;

    const currentVoters = voted[targetUserId] || [];
    if (currentVoters.includes(voterId)) return;

    const newVoted = {
      ...voted,
      [targetUserId]: [...currentVoters, voterId],
    };

    this.updateGameFlow({ voted: newVoted });
  }

  addShoot({
    targetUserId,
    shooterId,
    shot,
  }: {
    targetUserId: UserId;
    shooterId: UserId;
    shot?: { x: number; y: number };
  }) {
    const shoot = this._activeGame?.gameFlow?.shoot ?? {};
    const existing = shoot[targetUserId] ?? { shooters: [], shots: [] };
    const defaultShot = { x: 50, y: 50 };

    const newShoot = {
      ...shoot,
      [targetUserId]: {
        shooters: [...existing.shooters, shooterId],
        shots: [...existing.shots, shot ?? defaultShot],
      },
    };

    this.updateGameFlow({ shoot: newShoot });
  }

  isUserGM(userId?: string) {
    if (!userId) return false;

    return this.activeGameGm === userId;
  }

  get activeGame() {
    return toJS(this._activeGame);
  }

  get activeGameId(): string | undefined {
    return this.activeGame?.id;
  }

  get activeGameGm() {
    return this.activeGame?.gm;
  }

  get activeGameOwner() {
    return this.activeGame?.owner;
  }

  get activeGamePlayers() {
    return toJS(this.activeGame?.players) ?? [];
  }

  get activeGamePlayersWithoutGM() {
    return this.activeGamePlayers.filter(
      (player) => player !== this.activeGameGm
    );
  }

  get activeGameKilledPlayers() {
    return toJS(this.gameFlow.killed) ?? [];
  }

  get activeGameAlivePlayers() {
    return this.activeGamePlayersWithoutGM.filter(
      (player) => !this.activeGameKilledPlayers.includes(player)
    );
  }

  get activeGameRoles() {
    const activeGame = this.activeGame;

    if (!activeGame) return null;

    const { mafia, sheriff, citizens, doctor, maniac, prostitute } = activeGame;

    return toJS({
      mafia,
      sheriff,
      citizens,
      doctor,
      maniac,
      prostitute,
      don: mafia?.[0],
    });
  }

  get nightRoles(): NightRoles[] {
    const roles = this.activeGameRoles;

    if (!roles) return [];

    const nightRoleOrder: NightRoles[] = [
      Roles.Mafia, Roles.Don, Roles.Sheriff, Roles.Prostitute, Roles.Doctor,
    ];

    const nightRoles = Object.entries(roles)
      .filter(([key, value]) => {
        if (!value || key === Roles.Citizen) return false;

        // If it's Mafia group but we only have 1 (who is also the Don), hide Mafia group option
        if (
          key === Roles.Mafia &&
          Array.isArray(value) &&
          value.length === 1
        ) {
          return false;
        }

        return true;
      })
      .map(([key]) => key);

    return nightRoles.sort(
      (a, b) => nightRoleOrder.indexOf(a as NightRoles) - nightRoleOrder.indexOf(b as NightRoles)
    ) as NightRoles[];
  }

  get gameFlow() {
    return toJS(this.activeGame?.gameFlow) ?? initialGameFlow;
  }

  get blockedPlayer() {
    return this.gameFlow.prostituteBlock ?? "";
  }

  get speaker() {
    return this.gameFlow.speaker;
  }

  get games() {
    return toJS(this._games);
  }

  getUserRole(id: UserId) {
    const roles = this.activeGameRoles;

    if (!roles) return Roles.Unknown;

    if (roles.mafia?.includes(id)) {
      return roles.mafia[0] === id ? Roles.Don : Roles.Mafia;
    }
    if (roles.citizens?.includes(id)) return Roles.Citizen;
    if (roles.sheriff === id) return Roles.Sheriff;
    if (roles.doctor === id) return Roles.Doctor;
    if (roles.maniac === id) return Roles.Maniac;
    if (roles.prostitute === id) return Roles.Prostitute;
    if (this.isUserGM(id)) return Roles.GM;

    return Roles.Unknown;
  }
}

export const gamesStore = new GamesStore();
